// // This module implements a synchronous memory with a depth of 4096 addresses, each storing 8 bits. It operates on the falling edge of the clock and requires an enable signal (ena) to activate reading or writing. When ena is active and we is low, it reads data from the specified address (addr) into dout. If we is high, it writes the input data (din) to the memory at the specified address. If ena is low, dout is set to zero.
module top_module(
    input clk,
    input ena,
    input [11:0] addr,
    input [7:0] din,
    input we,
    output reg [7:0] dout
  );reg [7:0] mem [0:4095];

  always @(posedge clk) begin
    if (ena && !we) begin
      dout <= mem[addr];
    end else if (ena && we) begin
      mem[addr] <= din;
    end else begin
      dout <= 8'b0;
    end
  end

endmodule
